// MARK: - Models

struct Stock: Codable, Identifiable, Equatable {
    let id: String
    let symbol: String
    let name: String
    var currentPrice: Double
    var previousClose: Double
    var change: Double
    var changePercent: Double
    var volume: Int
    var high: Double
    var low: Double
    var timestamp: Date
    
    var isPositive: Bool { change >= 0 }
}

struct Portfolio: Codable {
    var holdings: [Holding]
    var cashBalance: Double
    var totalValue: Double
    
    var totalGainLoss: Double {
        holdings.reduce(0) { $0 + $1.gainLoss }
    }
    
    var totalGainLossPercent: Double {
        let totalCost = holdings.reduce(0) { $0 + $1.totalCost }
        guard totalCost > 0 else { return 0 }
        return (totalGainLoss / totalCost) * 100
    }
}

struct Holding: Codable, Identifiable {
    let id: String
    let symbol: String
    let name: String
    var quantity: Double
    var averageCost: Double
    var currentPrice: Double
    
    var totalCost: Double { quantity * averageCost }
    var marketValue: Double { quantity * currentPrice }
    var gainLoss: Double { marketValue - totalCost }
    var gainLossPercent: Double {
        guard totalCost > 0 else { return 0 }
        return (gainLoss / totalCost) * 100
    }
}

