// MARK: - Secure API Communication

class SecureAPIClient {
    static let shared = SecureAPIClient()
    
    private let session: URLSession
    private let baseURL: String
    private var authToken: String?
    private var refreshToken: String?
    private let keychainService = "com.tradingapp.keychain"
    
    private init() {
        let config = URLSessionConfiguration.default
        config.tlsMinimumSupportedProtocolVersion = .TLSv12
        config.httpAdditionalHeaders = [
            "Content-Type": "application/json",
            "Accept": "application/json",
            "X-App-Version": "1.0.0"
        ]
        config.timeoutIntervalForRequest = 30
        config.timeoutIntervalForResource = 60
        
        let delegate = SSLPinningDelegate()
        session = URLSession(configuration: config, delegate: delegate, delegateQueue: nil)
        baseURL = "https://api.tradingplatform.com/v1"
        
        loadTokensFromKeychain()
    }
    
    // MARK: - Keychain Operations
    
    func saveToKeychain(key: String, value: String) -> Bool {
        guard let data = value.data(using: .utf8) else { return false }
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainService,
            kSecAttrAccount as String: key,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        
        SecItemDelete(query as CFDictionary)
        let status = SecItemAdd(query as CFDictionary, nil)
        return status == errSecSuccess
    }
    
    func loadFromKeychain(key: String) -> String? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainService,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess, let data = result as? Data else { return nil }
        return String(data: data, encoding: .utf8)
    }
    
    func deleteFromKeychain(key: String) {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainService,
            kSecAttrAccount as String: key
        ]
        SecItemDelete(query as CFDictionary)
    }
    
    private func loadTokensFromKeychain() {
        authToken = loadFromKeychain(key: "auth_token")
        refreshToken = loadFromKeychain(key: "refresh_token")
    }
    
    func setTokens(auth: String, refresh: String) {
        authToken = auth
        refreshToken = refresh
        _ = saveToKeychain(key: "auth_token", value: auth)
        _ = saveToKeychain(key: "refresh_token", value: refresh)
    }
    
    func clearTokens() {
        authToken = nil
        refreshToken = nil
        deleteFromKeychain(key: "auth_token")
        deleteFromKeychain(key: "refresh_token")
    }
    
    // MARK: - Request Signing
    
    private func signRequest(_ request: inout URLRequest, body: Data?) {
        let timestamp = String(Int(Date().timeIntervalSince1970))
        let nonce = UUID().uuidString
        
        request.setValue(timestamp, forHTTPHeaderField: "X-Timestamp")
        request.setValue(nonce, forHTTPHeaderField: "X-Nonce")
        
        if let token = authToken {
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }
        
        let method = request.httpMethod ?? "GET"
        let path = request.url?.path ?? ""
        let bodyString = body.flatMap { String(data: $0, encoding: .utf8) } ?? ""
        let signaturePayload = "\(method)\(path)\(timestamp)\(nonce)\(bodyString)"
        
        if let secretKey = loadFromKeychain(key: "api_secret"),
           let keyData = secretKey.data(using: .utf8),
           let payloadData = signaturePayload.data(using: .utf8) {
            let key = SymmetricKey(data: keyData)
            let signature = HMAC<SHA256>.authenticationCode(for: payloadData, using: key)
            let signatureString = Data(signature).base64EncodedString()
            request.setValue(signatureString, forHTTPHeaderField: "X-Signature")
        }
    }
    
    // MARK: - Network Requests
    
    enum APIError: Error, LocalizedError {
        case invalidURL
        case noData
        case decodingError(Error)
        case serverError(Int, String)
        case networkError(Error)
        case unauthorized
        case rateLimited
        case insufficientFunds
        case marketClosed
        
        var errorDescription: String? {
            switch self {
            case .invalidURL: return "Invalid URL"
            case .noData: return "No data received"
            case .decodingError(let error): return "Data error: \(error.localizedDescription)"
            case .serverError(let code, let message): return "Server error (\(code)): \(message)"
            case .networkError(let error): return "Network error: \(error.localizedDescription)"
            case .unauthorized: return "Session expired. Please log in again."
            case .rateLimited: return "Too many requests. Please try again shortly."
            case .insufficientFunds: return "Insufficient funds for this trade."
            case .marketClosed: return "Market is currently closed."
            }
        }
    }
    
    func request<T: Decodable>(
        endpoint: String,
        method: String = "GET",
        body: Encodable? = nil,
        retryCount: Int = 2
    ) async throws -> T {
        guard let url = URL(string: "\(baseURL)\(endpoint)") else {
            throw APIError.invalidURL
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = method
        
        var bodyData: Data?
        if let body = body {
            let encoder = JSONEncoder()
            encoder.dateEncodingStrategy = .iso8601
            bodyData = try encoder.encode(AnyEncodable(body))
            request.httpBody = bodyData
        }
        
        signRequest(&request, body: bodyData)
        
        do {
            let (data, response) = try await session.data(for: request)
            
            guard let httpResponse = response as? HTTPURLResponse else {
                throw APIError.noData
            }
            
            switch httpResponse.statusCode {
            case 200...299:
                let decoder = JSONDecoder()
                decoder.dateDecodingStrategy = .iso8601
                do {
                    return try decoder.decode(T.self, from: data)
                } catch {
                    throw APIError.decodingError(error)
                }
            case 401:
                if retryCount > 0 {
                    try await refreshAuthToken()
                    return try await self.request(endpoint: endpoint, method: method, body: body, retryCount: retryCount - 1)
                }
                throw APIError.unauthorized
            case 429:
                throw APIError.rateLimited
            default:
                let message = String(data: data, encoding: .utf8) ?? "Unknown error"
                throw APIError.serverError(httpResponse.statusCode, message)
            }
        } catch let error as APIError {
            throw error
        } catch {
            throw APIError.networkError(error)
        }
    }
    
    private func refreshAuthToken() async throws {
        guard let refresh = refreshToken else {
            throw APIError.unauthorized
        }
        
        struct RefreshRequest: Encodable {
            let refreshToken: String
        }
        
        struct TokenResponse: Decodable {
            let accessToken: String
            let refreshToken: String
        }
        
        let response: TokenResponse = try await request(
            endpoint: "/auth/refresh",
            method: "POST",
            body: RefreshRequest(refreshToken: refresh),
            retryCount: 0
        )
        
        setTokens(auth: response.accessToken, refresh: response.refreshToken)
    }
}

// MARK: - SSL Pinning

class SSLPinningDelegate: NSObject, URLSessionDelegate {
    private let pinnedCertificateHashes: Set<String> = [
        "BBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBB="
    ]
    
    func urlSession(
        _ session: URLSession,
        didReceive challenge: URLAuthenticationChallenge,
        completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void
    ) {
        guard challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust,
              let serverTrust = challenge.protectionSpace.serverTrust else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        if SecTrustGetCertificateCount(serverTrust) > 0 {
            completionHandler(.useCredential, URLCredential(trust: serverTrust))
        } else {
            completionHandler(.cancelAuthenticationChallenge, nil)
        }
    }
}

// MARK: - Helper for Encodable

struct AnyEncodable: Encodable {
    private let _encode: (Encoder) throws -> Void
    
    init(_ wrapped: Encodable) {
        _encode = wrapped.encode
    }
    
    func encode(to encoder: Encoder) throws {
        try _encode(encoder)
    }
}

// MARK: - WebSocket for Real-Time Data

class WebSocketManager: NSObject, ObservableObject, URLSessionWebSocketDelegate {
    static let shared = WebSocketManager()
    
    @Published var isConnected = false
    @Published var lastPriceUpdate: [String: Double] = [:]
    
    private var webSocket: URLSessionWebSocketTask?
    private var session: URLSession?
    private var subscribedSymbols: Set<String> = []
    private var reconnectTimer: Timer?
    private var reconnectAttempts = 0
    private let maxReconnectAttempts = 5
    
    var onPriceUpdate: ((String, Double, Double) -> Void)?
    var onTradeUpdate: ((TradeOrder) -> Void)?
    
    private override init() {
        super.init()
    }
    
    func connect() {
        guard let url = URL(string: "wss://ws.tradingplatform.com/v1/stream") else { return }
        
        let config = URLSessionConfiguration.default
        session = URLSession(configuration: config, delegate: self, delegateQueue: OperationQueue.main)
        webSocket = session?.webSocketTask(with: url)
        webSocket?.resume()
        
        receiveMessage()
    }
    
    func disconnect() {
        webSocket?.cancel(with: .goingAway, reason: nil)
        webSocket = nil
        isConnected = false
        reconnectTimer?.invalidate()
    }
    
    func subscribe(symbols: [String]) {
        subscribedSymbols.formUnion(symbols)
        
        guard isConnected else { return }
        
        let message: [String: Any] = [
            "action": "subscribe",
            "symbols": symbols,
            "channels": ["trades", "quotes"]
        ]
        
        if let data = try? JSONSerialization.data(withJSONObject: message),
           let string = String(data: data, encoding: .utf8) {
            webSocket?.send(.string(string)) { error in
                if let error = error {
                    print("WebSocket send error: \(error)")
                }
            }
        }
    }
    
    func unsubscribe(symbols: [String]) {
        subscribedSymbols.subtract(symbols)
        
        guard isConnected else { return }
        
        let message: [String: Any] = [
            "action": "unsubscribe",
            "symbols": symbols
        ]
        
        if let data = try? JSONSerialization.data(withJSONObject: message),
           let string = String(data: data, encoding: .utf8) {
            webSocket?.send(.string(string)) { _ in }
        }
    }
    
    private func receiveMessage() {
        webSocket?.receive { [weak self] result in
            switch result {
            case .success(let message):
                switch message {
                case .string(let text):
                    self?.handleMessage(text)
                case .data(let data):
                    if let text = String(data: data, encoding: .utf8) {
                        self?.handleMessage(text)
                    }
                @unknown default:
                    break
                }
                self?.receiveMessage()
                
            case .failure(let error):
                print("WebSocket receive error: \(error)")
                self?.handleDisconnect()
            }
        }
    }
    
    private func handleMessage(_ text: String) {
        guard let data = text.data(using: .utf8),
              let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any] else { return }
        
        if let type = json["type"] as? String {
            switch type {
            case "quote":
                if let symbol = json["symbol"] as? String,
                   let price = json["price"] as? Double,
                   let change = json["change"] as? Double {
                    DispatchQueue.main.async {
                        self.lastPriceUpdate[symbol] = price
                        self.onPriceUpdate?(symbol, price, change)
                    }
                }
            case "trade_update":
                if let orderData = json["order"] as? [String: Any],
                   let jsonData = try? JSONSerialization.data(withJSONObject: orderData) {
                    let decoder = JSONDecoder()
                    decoder.dateDecodingStrategy = .iso8601
                    if let order = try? decoder.decode(TradeOrder.self, from: jsonData) {
                        DispatchQueue.main.async {
                            self.onTradeUpdate?(order)
                        }
                    }
                }
            default:
                break
            }
        }
    }
    
    private func handleDisconnect() {
        DispatchQueue.main.async {
            self.isConnected = false
            self.attemptReconnect()
        }
    }
    
    private func attemptReconnect() {
        guard reconnectAttempts < maxReconnectAttempts else { return }
        
        let delay = pow(2.0, Double(reconnectAttempts))
        reconnectTimer = Timer.scheduledTimer(withTimeInterval: delay, repeats: false) { [weak self] _ in
            self?.reconnectAttempts += 1
            self?.connect()
        }
    }
    
    // MARK: - URLSessionWebSocketDelegate
    
    func urlSession(_ session: URLSession, webSocketTask: URLSessionWebSocketTask, didOpenWithProtocol protocol: String?) {
        DispatchQueue.main.async {
            self.isConnected = true
            self.reconnectAttempts = 0
            if !self.subscribedSymbols.isEmpty {
                self.subscribe(symbols: Array(self.subscribedSymbols))
            }
        }
    }
    
    func urlSession(_ session: URLSession, webSocketTask: URLSessionWebSocketTask, didCloseWith closeCode: URLSessionWebSocketTask.CloseCode, reason: Data?) {
        handleDisconnect()
    }
}

// MARK: - Trading Service

class TradingService: ObservableObject {
    static let shared = TradingService()
    
    private let api = SecureAPIClient.shared
    
    @Published var portfolio: Portfolio?
    @Published var openOrders: [TradeOrder] = []
    @Published var orderHistory: [TradeOrder] = []
    @Published var watchlist: [WatchlistItem] = []
    @Published var isLoading = false
    @Published var error: String?
    
    private init() {
        setupWebSocketHandlers()
    }
    
    private func setupWebSocketHandlers() {
        WebSocketManager.shared.onPriceUpdate = { [weak self] symbol, price, change in
            self?.updateHoldingPrice(symbol: symbol, price: price)
            self?.updateWatchlistPrice(symbol: symbol, price: price, change: change)
        }
        
        WebSocketManager.shared.onTradeUpdate = { [weak self] order in
            self?.handleOrderUpdate(order)
        }
    }
    
    // MARK: - Portfolio
    
    @MainActor
    func fetchPortfolio() async {
        isLoading = true
        error = nil
        
        do {
            let portfolio: Portfolio = try await api.request(endpoint: "/portfolio")
            self.portfolio = portfolio
            
            let symbols = portfolio.holdings.map { $0.symbol }
            WebSocketManager.shared.subscribe(symbols: symbols)
        } catch {
            self.error = error.localizedDescription
        }
        
        isLoading = false
    }
    
    private func updateHoldingPrice(symbol: String, price: Double) {
        guard var portfolio = portfolio else { return }
        
        if let index = portfolio.holdings.firstIndex(where: { $0.symbol == symbol }) {
            portfolio.holdings[index].currentPrice = price
            portfolio.totalValue = portfolio.cashBalance + portfolio.holdings.reduce(0) { $0 + $1.marketValue }
            self.portfolio = portfolio
        }
    }
    
    private func updateWatchlistPrice(symbol: String, price: Double, change: Double) {
        if let index = watchlist.firstIndex(where: { $0.symbol == symbol }) {
            watchlist[index].currentPrice = price
            watchlist[index].change = change
        }
    }
    
    // MARK: - Trade Execution
    
    struct PlaceOrderRequest: Encodable {
        let symbol: String
        let side: OrderSide
        let type: OrderType
        let quantity: Double
        let limitPrice: Double?
        let stopPrice: Double?
        let timeInForce: TimeInForce
    }
    
    @MainActor
    func placeOrder(
        symbol: String,
        side: OrderSide,
        type: OrderType,
        quantity: Double,
        limitPrice: Double? = nil,
        stopPrice: Double? = nil,
        timeInForce: TimeInForce = .day
    ) async throws -> TradeConfirmation {
        // Validate order
        try validateOrder(symbol: symbol, side: side, quantity: quantity, limitPrice: limitPrice)
        
        let orderRequest = PlaceOrderRequest(
            symbol: symbol,
            side: side,
            type: type,
            quantity: quantity,
            limitPrice: limitPrice,
            stopPrice: stopPrice,
            timeInForce: timeInForce
        )
        
        let confirmation: TradeConfirmation = try await api.request(
            endpoint: "/orders",
            method: "POST",
            body: orderRequest
        )
        
        // Refresh portfolio after trade
        await fetchPortfolio()
        await fetchOpenOrders()
        
        return confirmation
    }
    
    private func validateOrder(symbol: String, side: OrderSide, quantity: Double, limitPrice: Double?) throws {
        guard quantity > 0 else {
            throw TradingError.invalidQuantity
        }
        
        guard !symbol.isEmpty else {
            throw TradingError.invalidSymbol
        }
        
        if side == .sell {
            guard let holding = portfolio?.holdings.first(where: { $0.symbol == symbol }),
                  holding.quantity >= quantity else {
                throw TradingError.insufficientShares
            }
        }
        
        if side == .buy {
            let estimatedCost = quantity * (limitPrice ?? 0)
            if let cash = portfolio?.cashBalance, estimatedCost > cash && limitPrice != nil {
                throw SecureAPIClient.APIError.insufficientFunds
            }
        }
    }
    
    @MainActor
    func cancelOrder(orderId: String) async throws {
        let _: TradeOrder = try await api.request(
            endpoint: "/orders/\(orderId)/cancel",
            method: "POST"
        )
        await fetchOpenOrders()
    }
    
    @MainActor
    func fetchOpenOrders() async {
        do {
            openOrders = try await api.request(endpoint: "/orders?status=open")
        } catch {
            self.error = error.localizedDescription
        }
    }
    
    @MainActor
    func fetchOrderHistory() async {
        do {
            orderHistory = try await api.request(endpoint: "/orders/history")
        } catch {
            self.error = error.localizedDescription
        }
    }
    
    private func handleOrderUpdate(_ order: TradeOrder) {
        if let index = openOrders.firstIndex(where: { $0.id == order.id }) {
            if order.status == .filled || order.status == .cancelled || order.status == .rejected {
                openOrders.remove(at: index)
                orderHistory.insert(order, at: 0)
            } else {
                openOrders[index] = order
            }
        }
        
        if order.status == .filled {
            Task { await fetchPortfolio() }
        }
    }
    
    // MARK: - Stock Data
    
    func fetchStockQuote(symbol: String) async throws -> Stock {
        try await api.request(endpoint: "/quotes/\(symbol)")
    }
    
    func fetchChartData(symbol: String, interval: String = "1D") async throws -> [ChartDataPoint] {
        try await api.request(endpoint: "/charts/\(symbol)?interval=\(interval)")
    }
    
    func searchStocks(query: String) async throws -> [Stock] {
        try await api.request(endpoint: "/search?q=\(query.addingPercentEncoding(withAllowedCharacters: .urlQueryAllowed) ?? query)")
    }
    
    // MARK: - Watchlist
    
    @MainActor
    func fetchWatchlist() async {
        do {
            watchlist = try await api.request(endpoint: "/watchlist")
            let symbols = watchlist.map { $0.symbol }
            WebSocketManager.shared.subscribe(symbols: symbols)
        } catch {
            self.error = error.localizedDescription
        }
    }
    
    @MainActor
    func addToWatchlist(symbol: String) async throws {
        struct AddRequest: Encodable { let symbol: String }
        let item: WatchlistItem = try await api.request(
            endpoint: "/watchlist",
            method: "POST",
            body: AddRequest(symbol: symbol)
        )
        watchlist.append(item)
        WebSocketManager.shared.subscribe(symbols: [symbol])
    }
    
    @MainActor
    func removeFromWatchlist(symbol: String) async throws {
        let _: EmptyResponse = try await api.request(
            endpoint: "/watchlist/\(symbol)",
            method: "DELETE"
        )
        watchlist.removeAll { $0.symbol == symbol }
        WebSocketManager.shared.unsubscribe(symbols: [symbol])
    }
}

struct EmptyResponse: Decodable {}

enum TradingError: Error, LocalizedError {
    case invalidQuantity
    case invalidSymbol
    case insufficientShares
    case invalidPrice
    case orderFailed(String)
    
    var errorDescription: String? {
        switch self {
        case .invalidQuantity: return "Please enter a valid quantity."
        case .invalidSymbol: return "Invalid stock symbol."
        case .insufficientShares: return "You don't have enough shares to sell."
        case .invalidPrice: return "Please enter a valid price."
        case .orderFailed(let reason): return "Order failed: \(reason)"
        }
    }
}

// MARK: - Authentication Service

class AuthService: ObservableObject {
    static let shared = AuthService()
    
    @Published var isAuthenticated = false
    @Published var isLoading = false
    @Published var error: String?
    
    private let api = SecureAPIClient.shared
    
    private init() {
        isAuthenticated = api.loadFromKeychain(key: "auth_token") != nil
    }
    
    struct LoginRequest: Encodable {
        let email: String
        let password: String
        let deviceId: String
    }
    
    struct AuthResponse: Decodable {
        let accessToken: String
        let refreshToken: String
        let userId: String
    }
    
    @MainActor
    func login(email: String, password: String) async {
        isLoading = true
        error = nil
        
        do {
            let deviceId = UIDevice.current.identifierForVendor?.uuidString ?? UUID().uuidString
            let request = LoginRequest(email: email, password: password, deviceId: deviceId)
            let response: AuthResponse = try await api.request(
                endpoint: "/auth/login",
                method: "POST",
                body: request
            )
            
            api.setTokens(auth: response.accessToken, refresh: response.refreshToken)
            isAuthenticated = true
        } catch {
            self.error = error.localizedDescription
        }
        
        isLoading = false
    }
    
    @MainActor
    func logout() {
        api.clearTokens()
        isAuthenticated = false
        WebSocketManager.shared.disconnect()
    }
    
    @MainActor
    func enableBiometric() async throws {
        // Store biometric flag
        _ = api.saveToKeychain(key: "biometric_enabled", value: "true")
    }
}

// MARK: - View Models

class TradeViewModel: ObservableObject {
    @Published var stock: Stock?
    @Published var orderSide: OrderSide = .buy
    @Published var orderType: OrderType = .market
    @Published var quantity: String = ""
    @Published var limitPrice: String = ""
    @Published var stopPrice: String = ""
    @Published var timeInForce: TimeInForce = .day
    @Published var isSubmitting = false
    @Published var confirmation: TradeConfirmation?
    @Published var error: String?
    @Published var showConfirmation = false
    @Published var chartData: [ChartDataPoint] = []
    
    private let tradingService = TradingService.shared
    
    var estimatedTotal: Double {
        let qty = Double(quantity) ?? 0
        let price: Double
        
        switch orderType {
        case .market:
            price = stock?.currentPrice ?? 0
        case .limit, .stopLimit:
            price = Double(limitPrice) ?? stock?.currentPrice ?? 0
        case .stopLoss:
            price = Double(stopPrice) ?? stock?.currentPrice ?? 0
        }
        
        return qty * price
    }
    
    var maxBuyQuantity: Int {
        guard let cash = tradingService.portfolio?.cashBalance,
              let price = stock?.currentPrice, price > 0 else { return 0 }
        return Int(cash / price)
    }
    
    var maxSellQuantity: Double {
        guard let holding = tradingService.portfolio?.holdings.first(where: { $0.symbol == stock?.symbol }) else { return 0 }
        return holding.quantity
    }
    
    var isValidOrder: Bool {
        guard let qty = Double(quantity), qty > 0 else { return false }
        
        switch orderType {
        case .market:
            return true
        case .limit:
            return Double(limitPrice) != nil && Double(limitPrice)! > 0
        case .stopLoss:
            return Double(stopPrice) != nil && Double(stopPrice)! > 0
        case .stopLimit:
            return Double(limitPrice) != nil && Double(limitPrice)! > 0 &&
                   Double(stopPrice) != nil && Double(stopPrice)! > 0
        }
    }
    
    @MainActor
    func loadStock(symbol: String) async {
        do {
            stock = try await tradingService.fetchStockQuote(symbol: symbol)
            chartData = try await tradingService.fetchChartData(symbol: symbol)
            WebSocketManager.shared.subscribe(symbols: [symbol])
            
            WebSocketManager.shared.onPriceUpdate = { [weak self] sym, price, change in
                if sym == symbol {
                    self?.stock?.currentPrice = price
                    self?.stock?.change = change
                }
            }
        } catch {
            self.error = error.localizedDescription
        }
    }
    
    @MainActor
    func submitOrder() async {
        guard isValidOrder, let symbol = stock?.symbol else { return }
        
        isSubmitting = true
        error = nil
        
        do {
            let qty = Double(quantity)!
            let limit = Double(limitPrice)
            let stop = Double(stopPrice)
            
            confirmation = try await tradingService.placeOrder(
                symbol: symbol,
                side: orderSide,
                type: orderType,
                quantity: qty,
                limitPrice: limit,
                stopPrice: stop,
                timeInForce: timeInForce
            )
            showConfirmation = true
        } catch {
            self.error = error.localizedDescription
        }
        
        isSubmitting = false
    }
}

class PortfolioViewModel: ObservableObject {
    @Published var portfolio: Portfolio?
    @Published var isLoading = false
    @Published var error: String?
    @Published var selectedTimeRange = "1D"
    @Published var performanceData: [ChartDataPoint] = []
    
    private let tradingService = TradingService.shared
    private var cancellables = Set<AnyCancellable>()
    
    init() {
        tradingService.$portfolio
            .receive(on: DispatchQueue.main)
            .assign(to: &$portfolio)
        
        tradingService.$error
            .receive(on: DispatchQueue.main)
            .assign(to: &$error)
    }
    
    @MainActor
    func loadPortfolio() async {
        isLoading = true
        await tradingService.fetchPortfolio()
        isLoading = false
    }
    
    @MainActor
    func refreshData() async {
        await tradingService.fetchPortfolio()
        await tradingService.fetchOpenOrders()
    }
}

class SearchViewModel: ObservableObject {
    @Published var searchText = ""
    @Published var results: [Stock] = []
    @Published var isSearching = false
    
    private let tradingService = TradingService.shared
    private var searchTask: Task<Void, Never>?
    
    func search() {
        searchTask?.cancel()
        
        guard searchText.count >= 1 else {
            results = []
            return
        }
        
        searchTask = Task { @MainActor in
            isSearching = true
            do {
                try await Task.sleep(nanoseconds: 300_000_000) // debounce
                results = try await tradingService.searchStocks(query: searchText)
            } catch {
                if !Task.isCancelled {
                    results = []
                }
            }
            isSearching = false
        }
    }
}

