// MARK: - Portfolio View Controller

class PortfolioViewController: UIViewController {
    private let viewModel = PortfolioViewModel()
    private var cancellables = Set<AnyCancellable>()
    
    private let scrollView = UIScrollView()
    private let contentStack = UIStackView()
    private let refreshControl = UIRefreshControl()
    
    // Header
    private let totalValueLabel = UILabel()
    private let totalChangeLabel = UILabel()
    private let cashBalanceLabel = UILabel()
    
    // Holdings table
    private let holdingsTableView = UITableView()
    private var holdings: [Holding] = []
    
    private let activityIndicator = UIActivityIndicatorView(style: .large)
    
    override func viewDidLoad() {
        super.viewDidLoad()
        title = "Portfolio"
        view.backgroundColor = .systemBackground
        navigationController?.navigationBar.prefersLargeTitles = true
        
        setupUI()
        bindViewModel()
        
        Task { await viewModel.loadPortfolio() }
    }
    
    private func setupUI() {
        scrollView.translatesAutoresizingMaskIntoConstraints = false
        scrollView.refreshControl = refreshControl
        refreshControl.addTarget(self, action: #selector(refresh), for: .valueChanged)
        view.addSubview(scrollView)
        
        contentStack.translatesAutoresizingMaskIntoConstraints = false
        contentStack.axis = .vertical
        contentStack.spacing = 16
        contentStack.layoutMargins = UIEdgeInsets(top: 16, left: 16, bottom: 16, right: 16)
        contentStack.isLayoutMarginsRelativeArrangement = true
        scrollView.addSubview(contentStack)
        
        // Portfolio Summary Card
        let summaryCard = createSummaryCard()
        contentStack.addArrangedSubview(summaryCard)
        
        // Holdings Section
        let holdingsHeader = UILabel()
        holdingsHeader.text = "Holdings"
        holdingsHeader.font = .systemFont(ofSize: 20, weight: .bold)
        contentStack.addArrangedSubview(holdingsHeader)
        
        holdingsTableView.translatesAutoresizingMaskIntoConstraints = false
        holdingsTableView.register(HoldingCell.self, forCellReuseIdentifier: "HoldingCell")
        holdingsTableView.dataSource = self
        holdingsTableView.delegate = self
        holdingsTableView.isScrollEnabled = false
        holdingsTableView.separatorStyle = .singleLine
        holdingsTableView.rowHeight = 72
        contentStack.addArrangedSubview(holdingsTableView)
        
        activityIndicator.translatesAutoresizingMaskIntoConstraints = false
        view.addSubview(activityIndicator)
        
        NSLayoutConstraint.activate([
            scrollView.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor),
            scrollView.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            scrollView.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            scrollView.bottomAnchor.constraint(equalTo: view.safeAreaLayoutGuide.bottomAnchor),
            
            contentStack.topAnchor.constraint(equalTo: scrollView.topAnchor),
            contentStack.leadingAnchor.constraint(equalTo: scrollView.leadingAnchor),
            contentStack.trailingAnchor.constraint(equalTo: scrollView.trailingAnchor),
            contentStack.bottomAnchor.constraint(equalTo: scrollView.bottomAnchor),
            contentStack.widthAnchor.constraint(equalTo: scrollView.widthAnchor),
            
            activityIndicator.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            activityIndicator.centerYAnchor.constraint(equalTo: view.centerYAnchor),
        ])
    }
    
    private func createSummaryCard() -> UIView {
        let card = UIView()
        card.backgroundColor = .secondarySystemBackground
        card.layer.cornerRadius = 16
        
        let stack = UIStackView()
        stack.axis = .vertical
        stack.spacing = 8
        stack.translatesAutoresizingMaskIntoConstraints = false
        card.addSubview(stack)
        
        let titleLabel = UILabel()
        titleLabel.text = "Total Portfolio Value"
        titleLabel.font = .systemFont(ofSize: 14, weight: .medium)
        titleLabel.textColor = .secondaryLabel
        
        totalValueLabel.font = .systemFont(ofSize: 36, weight: .bold)
        totalValueLabel.text = "$0.00"
        
        totalChangeLabel.font = .systemFont(ofSize: 16, weight: .semibold)
        totalChangeLabel.text = "+$0.00 (0.00%)"
        totalChangeLabel.textColor = .systemGreen
        
        let separator = UIView()
        separator.backgroundColor = .separator
        separator.heightAnchor.constraint(equalToConstant: 1).isActive = true
        
        cashBalanceLabel.font = .systemFont(ofSize: 14, weight: .medium)
        cashBalanceLabel.textColor = .secondaryLabel
        cashBalanceLabel.text = "Cash: $0.00"
        
        stack.addArrangedSubview(titleLabel)
        stack.addArrangedSubview(totalValueLabel)
        stack.addArrangedSubview(totalChangeLabel)
        stack.addArrangedSubview(separator)
        stack.addArrangedSubview(cashBalanceLabel)
        
        NSLayoutConstraint.activate([
            stack.topAnchor.constraint(equalTo: card.topAnchor, constant: 20),
            stack.leadingAnchor.constraint(equalTo: card.leadingAnchor, constant: 20),
            stack.trailingAnchor.constraint(equalTo: card.trailingAnchor, constant: -20),
            stack.bottomAnchor.constraint(equalTo: card.bottomAnchor, constant: -20)
        ])
        
        return card
    }
    
    private func bindViewModel() {
        viewModel.$portfolio
            .receive(on: DispatchQueue.main)
            .sink { [weak self] portfolio in
                self?.updatePortfolioUI(portfolio)
            }
            .store(in: &cancellables)
        
        viewModel.$isLoading
            .receive(on: DispatchQueue.main)
            .sink { [weak self] isLoading in
                if isLoading {
                    self?.activityIndicator.startAnimating()
                } else {
                    self?.activityIndicator.stopAnimating()
                    self?.refreshControl.endRefreshing()
                }
            }
            .store(in: &cancellables)
    }
    
    private func updatePortfolioUI(_ portfolio: Portfolio?) {
        guard let portfolio = portfolio else { return }
        
        totalValueLabel.text = formatCurrency(portfolio.totalValue)
        
        let gainLoss = portfolio.totalGainLoss
        let gainLossPercent = portfolio.totalGainLossPercent
        let sign = gainLoss >= 0 ? "+" : ""
        totalChangeLabel.text = "\(sign)\(formatCurrency(gainLoss)) (\(sign)\(String(format: "%.2f", gainLossPercent))%)"
        totalChangeLabel.textColor = gainLoss >= 0 ? .systemGreen : .systemRed
        
        cashBalanceLabel.text = "Cash Available: \(formatCurrency(portfolio.cashBalance))"
        
        holdings = portfolio.holdings
        holdingsTableView.reloadData()
        
        let tableHeight = CGFloat(holdings.count) * 72
        holdingsTableView.heightAnchor.constraint(equalToConstant: tableHeight).isActive = true
    }
    
    @objc private func refresh() {
        Task { await viewModel.refreshData() }
    }
    
    private func formatCurrency(_ value: Double) -> String {
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        formatter.currencyCode = "USD"
        return formatter.string(from: NSNumber(value: value)) ?? "$0.00"
    }
}

extension PortfolioViewController: UITableViewDataSource, UITableViewDelegate {
    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        holdings.count
    }
    
    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = tableView.dequeueReusableCell(withIdentifier: "HoldingCell", for: indexPath) as! HoldingCell
        cell.configure(with: holdings[indexPath.row])
        return cell
    }
    
    func tableView(_ tableView: UITableView, didSelectRowAt indexPath: IndexPath) {
        tableView.deselectRow(at: indexPath, animated: true)
        let holding = holdings[indexPath.row]
        let tradeVC = TradeViewController(symbol: holding.symbol)
        navigationController?.pushViewController(tradeVC, animated: true)
    }
}

// MARK: - Holding Cell

class HoldingCell: UITableViewCell {
    private let symbolLabel = UILabel()
    private let nameLabel = UILabel()
    private let priceLabel = UILabel()
    private let changeLabel = UILabel()
    private let quantityLabel = UILabel()
    private let valueLabel = UILabel()
    
    override init(style: UITableViewCell.CellStyle, reuseIdentifier: String?) {
        super.init(style: style, reuseIdentifier: reuseIdentifier)
        setupUI()
    }
    
    required init?(coder: NSCoder) { fatalError() }
    
    private func setupUI() {
        let leftStack = UIStackView(arrangedSubviews: [symbolLabel, nameLabel, quantityLabel])
        leftStack.axis = .vertical
        leftStack.spacing = 2
        
        let rightStack = UIStackView(arrangedSubviews: [priceLabel, changeLabel, valueLabel])
        rightStack.axis = .vertical
        rightStack.spacing = 2
        rightStack.alignment = .trailing
        
        let mainStack = UIStackView(arrangedSubviews: [leftStack, rightStack])
        mainStack.axis = .horizontal
        mainStack.distribution = .equalSpacing
        mainStack.translatesAutoresizingMaskIntoConstraints = false
        
        contentView.addSubview(mainStack)
        
        symbolLabel.font = .systemFont(ofSize: 16, weight: .bold)
        nameLabel.font = .systemFont(ofSize: 12, weight: .regular)
        nameLabel.textColor = .secondaryLabel
        quantityLabel.font = .systemFont(ofSize: 12, weight: .regular)
        quantityLabel.textColor = .secondaryLabel
        
        priceLabel.font = .systemFont(ofSize: 16, weight: .semibold)
        changeLabel.font = .systemFont(ofSize: 12, weight: .semibold)
        valueLabel.font = .systemFont(ofSize: 12, weight: .regular)
        valueLabel.textColor = .secondaryLabel
        
        NSLayoutConstraint.activate([
            mainStack.topAnchor.constraint(equalTo: contentView.topAnchor, constant: 8),
            mainStack.leadingAnchor.constraint(equalTo: contentView.leadingAnchor, constant: 16),
            mainStack.trailingAnchor.constraint(equalTo: contentView.trailingAnchor, constant: -16),
            mainStack.bottomAnchor.constraint(equalTo: contentView.bottomAnchor, constant: -8)
        ])
    }
    
    func configure(with holding: Holding) {
        symbolLabel.text = holding.symbol
        nameLabel.text = holding.name
        quantityLabel.text = "\(String(format: "%.2f", holding.quantity)) shares"
        
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        
        priceLabel.text = formatter.string(from: NSNumber(value: holding.currentPrice))
        valueLabel.text = "Value: \(formatter.string(from: NSNumber(value: holding.marketValue)) ?? "$0")"
        
        let sign = holding.gainLoss >= 0 ? "+" : ""
        changeLabel.text = "\(sign)\(formatter.string(from: NSNumber(value: holding.gainLoss)) ?? "$0") (\(sign)\(String(format: "%.2f", holding.gainLossPercent))%)"
        changeLabel.textColor = holding.gainLoss >= 0 ? .systemGreen : .systemRed
    }
}

