        view.addGestureRecognizer(tapGesture)
    }
    
    private func createFieldLabel(_ text: String) -> UILabel {
        let label = UILabel()
        label.text = text
        label.font = .systemFont(ofSize: 13, weight: .medium)
        label.textColor = .secondaryLabel
        return label
    }
    
    private func configureTextField(_ field: UITextField, placeholder: String) {
        field.placeholder = placeholder
        field.borderStyle = .roundedRect
        field.backgroundColor = .tertiarySystemBackground
        field.font = .systemFont(ofSize: 16)
        field.heightAnchor.constraint(equalToConstant: 44).isActive = true
    }
    
    private func bindViewModel() {
        viewModel.$stock
            .receive(on: DispatchQueue.main)
            .sink { [weak self] stock in
                self?.updateStockInfo(stock)
            }
            .store(in: &cancellables)
        
        viewModel.$error
            .receive(on: DispatchQueue.main)
            .sink { [weak self] error in
                self?.errorLabel.text = error
                self?.errorLabel.isHidden = error == nil
            }
            .store(in: &cancellables)
        
        viewModel.$showConfirmation
            .receive(on: DispatchQueue.main)
            .sink { [weak self] show in
                if show {
                    self?.showConfirmationAlert()
                }
            }
            .store(in: &cancellables)
        
        viewModel.$isSubmitting
            .receive(on: DispatchQueue.main)
            .sink { [weak self] isSubmitting in
                self?.submitButton.isEnabled = !isSubmitting
                self?.submitButton.setTitle(isSubmitting ? "Placing Order..." : "Place Order", for: .normal)
                self?.submitButton.alpha = isSubmitting ? 0.6 : 1.0
            }
            .store(in: &cancellables)
    }
    
    private func updateStockInfo(_ stock: Stock?) {
        guard let stock = stock else { return }
        
        stockNameLabel.text = stock.name
        
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        
        currentPriceLabel.text = formatter.string(from: NSNumber(value: stock.currentPrice))
        
        let sign = stock.change >= 0 ? "+" : ""
        priceChangeLabel.text = "\(sign)\(formatter.string(from: NSNumber(value: stock.change)) ?? "$0") (\(sign)\(String(format: "%.2f", stock.changePercent))%)"
        priceChangeLabel.textColor = stock.isPositive ? .systemGreen : .systemRed
        
        updateEstimatedTotal()
    }
    
    private func updateEstimatedTotal() {
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        estimatedTotalLabel.text = "Estimated Total: \(formatter.string(from: NSNumber(value: viewModel.estimatedTotal)) ?? "$0.00")"
    }
    
    @objc private func sideChanged() {
        viewModel.orderSide = segmentedControl.selectedSegmentIndex == 0 ? .buy : .sell
        submitButton.backgroundColor = viewModel.orderSide == .buy ? .systemGreen : .systemRed
        submitButton.setTitle(viewModel.orderSide == .buy ? "Place Buy Order" : "Place Sell Order", for: .normal)
    }
    
    @objc private func orderTypeChanged() {
        let types = OrderType.allCases
        viewModel.orderType = types[orderTypeControl.selectedSegmentIndex]
        
        switch viewModel.orderType {
        case .market:
            limitPriceStack.isHidden = true
            stopPriceStack.isHidden = true
        case .limit:
            limitPriceStack.isHidden = false
            stopPriceStack.isHidden